fn run(filename: &str) -> Result<(), Box<dyn Error>> {
    let mut reader = csv::ReaderBuilder::new().from_path(filename)?;
    let values: Vec<f64> = reader
        .deserialize()
        .filter_map(Result::ok)
        .filter_map(|record: (String, String)| record.1.parse().ok())
        .collect();

    let statistics = Statistics::new(&values).unwrap();

    println!("Mean: {:.2}", statistics.mean());
    println!("Standard deviation: {:.2}", statistics.std_dev());

    Ok(())
}
```

